var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"으흐흑… 드레카….","JPN":"うううっ……ドレカ……","ENG":"Hngh... Dreka...","TWN":"嗚嗚嗚……德蕾卡……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"안돼 드레카… 죽으면 안돼….","JPN":"ダメ、ドレカ……死んじゃダメ……","ENG":"No, Dreka... Don't die...","TWN":"不行，德蕾卡……不能死……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"미안해… 정말 미안해….","JPN":"ごめん……本当にごめんね……","ENG":"I'm sorry... I'm so sorry...","TWN":"對不起……真的對不起……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"내가… 지켜줬어야 했는데….","JPN":"私が……守ってあげるべきだったのに……","ENG":"I should've... protected you...","TWN":"我……本該保護你的……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그치만… 너무 무서웠단 말이야….","JPN":"でも……すごく怖かったの……","ENG":"But... I was so scared...","TWN":"可是……真的太可怕了……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"나까지 죽으면… 다음은 없어… 나도 어쩔 수 없었단 말이야….","JPN":"私まで死んじゃうと……次はない……私も仕方なかったのよ……","ENG":"But if I die too... there won't be a next time... So, there was nothing I could do...","TWN":"如果連我也死了……就沒有下一次了……我也沒辦法……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"괘, 괜찮아 드레카. 다시 살아날 수 있어.","JPN":"だ、大丈夫だよ、ドレカ。また蘇られる。","ENG":"I-it's okay, Dreka. You'll be back on your feet in no time.","TWN":"沒，沒事的，德蕾卡，你還能活過來的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"본부로 돌아가면 분명히 되살려줄 거야….","JPN":"本部に戻ったらきっと蘇らせてくれる……","ENG":"Once we get to the headquarters, I'm sure they'll revive you.","TWN":"回到總部後一定會救活你的……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"언니가… 꼭 다시 살려줄게….","JPN":"姉さんが……きっとまた蘇らせてあげるよ……","ENG":"Your big sister will... make it so...","TWN":"姊姊……一定會想辦法讓你……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그러니까… 조금만 참아줘 드레카….","JPN":"だから……少しだけ我慢して、ドレカ……","ENG":"So... just hold on a little longer, Dreka...","TWN":"所以……再忍耐一下，德蕾卡……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"헉! 누, 누가 왔나 봐…!","JPN":"はっ！　だ、誰かが来たみたい……！","ENG":"*Gasp* I-I think someone's here...!","TWN":"啊！有，有人來了……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"지금 그걸 숨었다고 생각하는 거야?","JPN":"今それ、隠れてるつもり？","ENG":"You call that hiding?","TWN":"你覺得這樣就能躲起來嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"빨리 나와.","JPN":"早く出てきて。","ENG":"Get out.","TWN":"出來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"………!","JPN":"………！","ENG":"...!","TWN":"………！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나오라고.","JPN":"出てこいってば。","ENG":"Now.","TWN":"給我出來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"………!!","JPN":"………！！","ENG":"...!!","TWN":"………！！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"으아악! 미, 미안해…! 사샤는 나도 어쩔 수 없었어…!","JPN":"わああっ！　ご、ごめんなさい……！　サシャのことは仕方なかったの……！","ENG":"Ahh! I-I'm sorry...! There was nothing I could do about Sasha...!","TWN":"啊啊啊！對，對不起……！莎夏的事，我也沒辦法……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"흑흑… 정말… 정말 미안해….","JPN":"ううっ……本当に……本当にごめん……","ENG":"*Sniffle* I'm... really sorry...","TWN":"嗚嗚……真的……真的對不起……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"나도… 나도 죽이고 싶지 않았단 말이야. 엉엉…!!","JPN":"私も……私も殺したくなかったんだよ。わーん……！！","ENG":"I... I didn't want to kill her too! WAAAAH...!!","TWN":"我也……我也不想殺人的。嗚嗚……！！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"옆에서 실컷 방관해 놓고 넌 멀쩡히 돌아갈 생각이야?","JPN":"隣でただ傍観してたくせに、あなたは何事もなかったかのように帰るつもり？","ENG":"Did you think you'd go home unharmed after you just sat on your hands and watched everything happen?","TWN":"你以為只是在旁邊袖手旁觀，就能安然無恙地回去？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분명 다른 아이의 메모리 코어를 넣어 재활용할 생각이지?","JPN":"そのドレカバクの死体、きっと他の子のメモリーコアを入れてまた使う気でしょう？","ENG":"Drekavac's corpse... You're thinking of reusing it by putting in another kid's memory core, aren't you?","TWN":"你打算用其他孩子的記憶核心，裝到德蕾卡娃克的殘骸裡吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그렇게 두지 않겠어.","JPN":"そうはさせない。","ENG":"I'm not going to let you do that.","TWN":"我不會讓你這麼做的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L38_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"아, 아냐! 절대 그런 짓은 안할 테니까…!","JPN":"ち、違うよ！　絶対そんなことしないから……！","ENG":"N-no! I would never–!","TWN":"啊，不是的！我絕對不會做那種事……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"으아아아악!","JPN":"うわあああ！","ENG":"Aaaargh!","TWN":"呃啊啊啊啊！！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"사, 살려줘 제발… 아픈 건 이제 싫어….","JPN":"た、助けて、お願い……もう痛いのはイヤ……","ENG":"P-please... stop... I don't want to be in pain anymore...","TWN":"饒，饒命…求求你…我不想再痛了…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"드레카바크의 시체까지 포기하면서 목숨을 구걸하다니….","JPN":"ドレカバクの死体を放り出してまで命乞いするなんて……","ENG":"I can't believe you threw away Drekavac's corpse just to beg for your life...","TWN":"竟然連德蕾克的屍體都可以放棄，只為了要活命……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너 정말 언니가 맞긴 해?!","JPN":"あなた、本当にお姉さんなの！？","ENG":"Are you even really her big sister?!","TWN":"你真的是姊姊嗎？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히익…!","JPN":"ひいっ……！","ENG":"Eeek...!","TWN":"啊……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"생각해 보니 이상해. 너도 마트료시카 인형인데, 그냥 겁쟁이잖아.","JPN":"考えてみたらおかしい。あなたもマトリョシカ人形なのに、ただの臆病者じゃない。","ENG":"Now that I think about it, you're weird. You're also a Matryoshka Doll, but you're a coward.","TWN":"仔細想想很奇怪。你也是個俄羅斯娃娃，但卻是個膽小鬼。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>역시 넌 뭔가 숨기고 있는 게 분명해.</color>","JPN":"<color=#ffd34c>やっぱりあなたは何かを隠してる。</color>","ENG":"<color=#ffd34c>I'm certain that you're hiding something from me.</color>","TWN":"<color=#ffd34c>你一定有在隱瞞些什麼。</color>"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"저 꼬맹이와 드레카바크의 시체는 우리 민병단이 맡지. 이쪽도 묻고 싶은 게 많아.","JPN":"あのチビとドレカバクの死体は、俺たち民兵団が引取る。こちらからも聞きたいことがたくさんあるからな。","ENG":"The militia will take that kid and the corpse of Drekavac. We also have a lot of questions that need answers.","TWN":"那個小鬼和德蕾卡娃克的屍體交給我們民兵團吧，我們也有很多問題要問。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"넌 오늘부터 24시간 감시 될거다.","JPN":"お前は今日から24時間監視される。","ENG":"You will be under constant surveillance beginning today.","TWN":"從今天起，你會被24小時監視。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"허튼짓 했다간, 곧바로 벌집으로 만들어줄 테니까, 꿈도 꾸지 말라고.","JPN":"疑われるようなことをすれば、すぐ蜂の巣にしてやるから、要らぬことは考えるな。","ENG":"Don't try anything stupid, or I'll make sure to shoot you on the spot.","TWN":"如果敢亂來，會立刻把你打成蜂窩，別做夢了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L5_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히, 히익…! 아픈건 싫어요…!","JPN":"ひ、ひいっ……！　痛いのはイヤです……！","ENG":"E-eeek...! Pain is bad...!","TWN":"嗚嗚……！我不想受苦……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"시, 시키는대로 할게요. 제발…!","JPN":"い、言われたとおりにします。お願い……！","ENG":"I-I'll do anything you ask. So, please...!","TWN":"我，我會照做的，求求你……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"연구소 놈들은 모두 도망친 것 같다. 드레카바크와 싸우는 동안 퇴각한 것 같아.","JPN":"研究所のやつらはみんな逃げたようだな。ドレカバクと戦っている間に退却したようだ。","ENG":"Looks like all the researchers have already run away. Guess they fled while you were fighting with Drekavac.","TWN":"研究所的人似乎都逃跑了，在與德蕾卡娃克戰鬥時撤退了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"서류 한장 조차 남지 않았더군.","JPN":"書類の一枚も残ってなかった。","ENG":"They didn't even leave a single document behind.","TWN":"連一張文件都沒留下。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"이 둘은 장기말 중, 하나에 불과했다는 거겠지.","JPN":"この二人は捨て駒に過ぎなかったってことだろう。","ENG":"Which means that these two were mere pawns.","TWN":"這兩人只是棋子之一。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"마을도 완전히 쑥대밭이 되었어. 재건하는데 쉽지 않겠는걸.","JPN":"村も完全に崩壊している。復興するのに苦労しそうだ。","ENG":"The village is completely devastated. It won't be easy rebuilding it.","TWN":"村子也完全被毀了，重建起來也不容易。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"재건은 나한테 맡겨줘. 사샤의 능력을 사용할 수 있으니까.","JPN":"それなら私に任せて。サシャの能力を使えるから。","ENG":"Leave that to me. I'm able to use Sasha's ability now.","TWN":"重建的事就交給我吧，我現在繼承了莎夏的能力。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마브카.","JPN":"マブカ。","ENG":"Mavka.","TWN":"瑪卡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤는… 정말 좋은 아이였다.","JPN":"サシャは……本当にいい子だった。","ENG":"Sasha was... a really good kid.","TWN":"莎夏……她是個好孩子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"……유감이구나.","JPN":"……残念だな。","ENG":"...I'm sorry for your loss.","TWN":"……只可惜。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그리고… 정말 미안하다.","JPN":"そして……本当にすまない。","ENG":"And... I owe you an apology.","TWN":"還有……我欠你一個道歉。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사과하지 않아도 돼.","JPN":"謝らなくていいよ。","ENG":"You don't need to apologize.","TWN":"不需要道歉。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그럼 이제부터 어쩔 생각이야?","JPN":"じゃあ、これからどうするつもりなの？","ENG":"So, what are you going to do now?","TWN":"那麼，接下來你打算怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"마을을 지킬 거야.","JPN":"村を守る。","ENG":"I'm going to protect the village.","TWN":"我想要守護這個村莊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"여긴 사샤의 마을이면서….","JPN":"ここはサシャの村で……","ENG":"This is Sasha's village...","TWN":"這裡是莎夏的村子……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이젠 내 마을이기도 하니까.","JPN":"私の村でもあるから。","ENG":"and mine as well, now.","TWN":"現在也是我的村子了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"북방군들은 분명 우릴 주시하고 있어.","JPN":"北方軍は確かに私たちを睨んでる。","ENG":"The Northern Army will be keeping an eye on us.","TWN":"北方軍肯定在監視我們。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"걱정하지 마. 내가 있는 한, 놈들도 각오를 다져야 할 테니까.","JPN":"心配しないで。私がいる限り、やつらも覚悟を決めないといけないはずだから。","ENG":"But don't worry. As long as I'm here, they'll need to be fully prepared to attack us again.","TWN":"但請放心，有我在，他們也得做好覺悟。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"혼자서 모든 짐을 감당하려 하지 마라.","JPN":"一人ですべてを背負おうとするな。","ENG":"Don't try to carry all the burden yourself.","TWN":"不要一個人承擔所有的重擔。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그래. 필요한 거 있으면 말하고.","JPN":"そうよ。必要なことがあったら言って。","ENG":"Yeah. Just let us know if you need anything.","TWN":"是啊，有需要的話就直說。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응… 고마워.","JPN":"うん……ありがとう。","ENG":"Okay... thanks.","TWN":"嗯……謝謝。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 이제 그만 마을로 돌아가자.","JPN":"じゃあ、村に戻ろう。","ENG":"Then, let's head back home.","TWN":"那，現在我們就回村子去吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};